mapper.select:
    	SELECT CASE WHEN COUNT(1) > 0 THEN TRUE ELSE FALSE END
	    FROM repeat_block_day d
	    INNER JOIN repeat_block rb ON d.repeat_block_id = rb.repeat_block_id
	    WHERE rb.line_id = #{lineId}
	      AND d.day_of_week = #{dayOfWeek}
	      AND d.start_at = #{startAt}
	      AND d.end_at = #{endAt}
	      AND rb.deleted_at IS NULL
	      AND d.deleted_at IS NULL
